    query = f"SELECT COUNT(*) as cnt FROM analytics.{event['table']} WHERE dt = '{event['date']}'"
    response = athena.start_query_execution(
        QueryString=query,
        QueryExecutionContext={'Database': 'analytics'},
        ResultConfiguration={'OutputLocation': 's3://acme-athena-results/dq/'}
